import subprocess
import sys
def oligotm(seq):
    cmd = ['oligotm', '-tp', '1', '-sc', '1', '-mv', '50', '-dv', '2', '-n', '0.8', '-d', '500', seq]
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, check=True)
        lines = result.stdout.strip().split()
        for token in lines:
            if token.replace('.', '').isdigit():
                return float(token)
        return 60.0
    except:
        return None
def rc(seq):
    comp = {'A':'T','T':'A','C':'G','G':'C','a':'t','t':'a','c':'g','g':'c'}
    return ''.join(comp.get(base, base) for base in reversed(seq))
seqs = {}
with open('sequences.fasta') as f:
